<?php
require_once 'config.php'; require_once 'check_access.php'; $conn=getDB(); $uid=$_SESSION['user_id']; $att=$conn->query("SELECT date,status,remarks FROM attendance WHERE user_id=$uid ORDER BY date DESC LIMIT 30"); $disc=$conn->query("SELECT action,reason,suspension_end,created_at FROM discipline_log WHERE user_id=$uid ORDER BY created_at DESC"); ?>
<!DOCTYPE html><html><head><title>Attendance</title><link rel="stylesheet" href="style.css"></head><body><div class="container"><div class="header"><h1>📅 My Attendance</h1><a href="dashboard.php">Dashboard</a><a href="logout.php" class="logout">Logout</a></div><h2>Attendance (last 30 days)</h2><table class="data-table"><?php while($r=$att->fetch_assoc()):?><tr><td><?=$r['date']?></td><td><?=$r['status']?></td><td><?=$r['remarks']?></td></tr><?php endwhile;?></table><h2>Discipline History</h2><table class="data-table"><?php while($d=$disc->fetch_assoc()):?><tr><td><?=$d['created_at']?></td><td><?=strtoupper($d['action'])?></td><td><?=$d['reason']?></td></tr><?php endwhile;?></table><div class="footer"><a href="dashboard.php">← Back</a></div></div></body></html>